import type { MapRef } from '@vis.gl/react-maplibre';

import { attachImageToMap } from './attach-image-to-map.js';
import { getScaledSymbolSize } from './get-scaled-symbol-size.js';

export const attachImageFromText = (
  map: MapRef,
  text: string,
  name: string,
  outputSize?: number,
) => {
  const scaledTextSymbolSize = getScaledSymbolSize(outputSize);
  const canvas = document.createElement('canvas');
  // Create a canvas with the default icon size (dpr for retina displays)
  canvas.width = scaledTextSymbolSize;
  canvas.height = scaledTextSymbolSize;
  const ctx = canvas.getContext('2d') ?? new CanvasRenderingContext2D();
  ctx.imageSmoothingEnabled = false;
  ctx.font = `${scaledTextSymbolSize}px DynatraceFlow`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(text, scaledTextSymbolSize / 2, scaledTextSymbolSize / 2);

  const img = new Image(scaledTextSymbolSize, scaledTextSymbolSize);
  img.addEventListener('load', () => {
    attachImageToMap(map, img, name, false);
  });
  img.src = canvas.toDataURL('image/png');
};
